package com.google.gson;

import com.google.gson.internal.LazilyParsedNumber;
import java.math.BigDecimal;
import java.math.BigInteger;
import java.util.Objects;
public final class JsonPrimitive extends JsonElement{
@Override
  public boolean getAsBoolean() {
    if (isBoolean()) {
      return (Boolean) value;
    }
	// Check to see if the value as a String is "true" in any case.
    return Boolean.parseBoolean(getAsString());
  }
private final Object value;
@SuppressWarnings("deprecation") // superclass constructor public  JsonPrimitive(Boolean bool)
@SuppressWarnings("deprecation") // superclass constructor public  JsonPrimitive(Number number)
@SuppressWarnings("deprecation") // superclass constructor public  JsonPrimitive(String string)
@SuppressWarnings("deprecation") // superclass constructor public  JsonPrimitive(Character c)
@Override public JsonPrimitive deepCopy()
public boolean isBoolean()
public boolean isNumber()
@Override public Number getAsNumber()
public boolean isString()
@Override public String getAsString()
@Override public double getAsDouble()
@Override public BigDecimal getAsBigDecimal()
@Override public BigInteger getAsBigInteger()
@Override public float getAsFloat()
@Override public long getAsLong()
@Override public short getAsShort()
@Override public int getAsInt()
@Override public byte getAsByte()
@Deprecated @Override public char getAsCharacter()
@Override public int hashCode()
@Override public boolean equals(Object obj)
private static boolean isIntegral(JsonPrimitive primitive)
}
